var body = $input.first().json.body || $input.first().json;

if (!body.documentType) throw new Error('documentType is required');
if (!body.documentId) throw new Error('documentId is required');
if (!body.recipientEmail) throw new Error('recipientEmail is required');

var typeMap = {
  'devis': '/api/devis/',
  'facture': '/api/invoices/',
  'bon_commande': '/api/bons-commande/',
  'proforma': '/api/proforma/',
  'avoir': '/api/avoir/',
  'facture_achat': '/api/invoices/'
};

var prefix = typeMap[body.documentType];
if (!prefix) throw new Error('documentType invalide: ' + body.documentType + '. Valeurs: devis, facture, bon_commande, proforma, avoir, facture_achat');

var pdfUrl = 'https://api.talosprimes.com' + prefix + body.documentId + '/pdf';

var typeLabels = {
  'devis': 'Devis',
  'facture': 'Facture',
  'bon_commande': 'Bon de commande',
  'proforma': 'Proforma',
  'avoir': 'Avoir',
  'facture_achat': 'Facture d\'achat'
};

return [{ json: {
  documentType: body.documentType,
  documentId: body.documentId,
  recipientEmail: body.recipientEmail,
  subject: body.subject || (typeLabels[body.documentType] + ' - TalosPrimes'),
  message: body.message || ('Bonjour,\n\nVeuillez trouver ci-joint votre ' + typeLabels[body.documentType].toLowerCase() + '.\n\nCordialement,\nTalosPrimes'),
  pdfUrl: pdfUrl,
  fileName: (typeLabels[body.documentType] || 'Document') + ' ' + (body.clientName || body.numeroDocument || body.documentId) + '.pdf',
  typeLabel: typeLabels[body.documentType],
  numeroDocument: body.numeroDocument || ''
} }];

var parser = $('02. Parser').first().json;

// Build HTML email (sans signature)
var msg = parser.message || 'Veuillez trouver ci-joint votre document.';
var paragraphs = msg.split('\n\n');
var htmlParagraphs = paragraphs.map(function(p) {
  var escaped = p.replace(/\n/g, '<br>');
  return '<p style="margin:0 0 14px 0;line-height:1.6;font-size:14px;">' + escaped + '</p>';
}).join('');

var htmlMessage = '<div style="font-family:Segoe UI,Arial,sans-serif;max-width:600px;margin:0 auto;color:#333;">'
  + '<div style="padding:0 0 20px 0;">' + htmlParagraphs + '</div>'
  + '</div>';

// Get binary data from input (direct pipeline from Download PDF)
var downloadItem = $input.first();
var binaryData = downloadItem.binary || {};
var finalBinary = {};

var keys = Object.keys(binaryData);
if (keys.length > 0) {
  var firstKey = keys[0];
  // Use direct reference - do NOT copy with Object.assign (loses n8n internal binary ID)
  finalBinary.data = binaryData[firstKey];
  finalBinary.data.fileName = parser.fileName;
  finalBinary.data.mimeType = 'application/pdf';
} else {
  throw new Error('Le PDF n\'a pas pu être téléchargé - aucune donnée binaire reçue du noeud Download PDF');
}

return [{
  json: {
    toEmail: parser.recipientEmail,
    subject: parser.subject,
    message: htmlMessage,
    fileName: parser.fileName,
    documentType: parser.documentType,
    documentId: parser.documentId
  },
  binary: finalBinary
}];

var email = $('07. Gmail Envoyer PJ').first().json;
var parser = $('02. Parser').first().json;

return [{ json: {
  success: true,
  message: parser.typeLabel + ' envoyé(e) par email à ' + parser.recipientEmail + ' avec pièce jointe PDF',
  emailId: email.id || null,
  recipientEmail: parser.recipientEmail,
  documentType: parser.documentType,
  documentId: parser.documentId,
  fileName: parser.fileName
} }];
